  texture.type = TYPE_MAP[vkFormat];
  texture.format = FORMAT_MAP[vkFormat];
  texture.encoding = ENCODING_MAP[vkFormat] || LinearEncoding;
  texture.needsUpdate = true; //

  return Promise.resolve(texture);
}

export { KTX2Loader };
